import { Button, Card, CardContent, CardHeader, Container, Dialog, DialogContent, DialogTitle, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'




export default function Quiz() {
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    };
    const closeQuiz = () => {
        setQuiz(false)
    };

  return (
    <>
    <Button variant='contained' color='secondary' onClick={openQuiz}>
        Open Dialog
    </Button>
        <Dialog open={quiz} onClose={closeQuiz} fullScreen>
            <DialogTitle>Web Application Development</DialogTitle>
            <DialogContent>
                <Card elevation={3} >
                    <Container>
                    <CardHeader title='Quiz 1' />
                    <CardContent>
                        <Typography>
                            Questions will be here.
                        </Typography>
                    </CardContent>
                    </Container>
                </Card>
            </DialogContent>
        </Dialog>
    </>
  )
}
